#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B, C;
        scanf("%d %d %d", &A, &B, &C);
        int total = A + B + C;
        if (A >= 10 && B >= 10 && C >= 10 && total >= 100)
            printf("PASS\n");
        else
            printf("FAIL\n");
    }
    return 0;
}

