#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it))
        total = A + B + C
        if A >= 10 and B >= 10 and C >= 10 and total >= 100:
            out_lines.append("PASS")
        else:
            out_lines.append("FAIL")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

